import React, { useEffect, useState, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const AdminDashboard = () => {
  const [user, setUser] = useState(null);
  const [pendingUsers, setPendingUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [actionLoading, setActionLoading] = useState('');
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');
  const navigate = useNavigate();
  const token = localStorage.getItem('token');

  const headers = {
    Authorization: `Bearer ${token}`
  };

  const loadProfile = useCallback(async () => {
    if (!token) {
      navigate('/login');
      return;
    }

    try {
      const res = await axios.get('http://localhost:5000/api/auth/profile', { headers });
      if (!res.data.isAdmin) {
        navigate('/dashboard');
        return;
      }
      setUser(res.data);
    } catch (err) {
      localStorage.removeItem('token');
      localStorage.removeItem('isAdmin');
      navigate('/login');
    }
  }, [headers, navigate, token]);

  const loadPendingKyc = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/admin/kyc/pending', { headers });
      setPendingUsers(res.data);
    } catch (err) {
      setError(err?.response?.data?.error || 'Could not load pending KYC applications');
    }
  };

  useEffect(() => {
    loadProfile();
  }, [loadProfile]);

  useEffect(() => {
    if (user?.isAdmin) {
      loadPendingKyc();
      setLoading(false);
    }
  }, [user]);

  const changeKycStatus = async (userId, type) => {
    setActionLoading(userId);
    setError('');
    setMessage('');

    try {
      const endpoint = `http://localhost:5000/api/admin/kyc/${userId}/${type}`;
      const res = await axios.put(endpoint, {}, { headers });
      setMessage(res.data.message);
      await loadPendingKyc();
    } catch (err) {
      setError(err?.response?.data?.error || 'Action failed');
    } finally {
      setActionLoading('');
    }
  };

  const getFileUrl = (filePath) => {
    if (!filePath) return null;
    const normalized = filePath.replace(/\\/g, '/');
    return `http://localhost:5000/${normalized}`;
  };

  if (loading) {
    return <div className="page-content"><div className="card">Loading admin dashboard...</div></div>;
  }

  return (
    <div className="dashboard-layout">
      <aside className="dashboard-sidebar">
        <div className="sidebar-user">
          <div className="user-avatar">A</div>
          <div className="user-info">
            <h4>{user?.username || 'Admin'}</h4>
            <p>{user?.email || 'admin@charity.com'}</p>
          </div>
        </div>

        <nav className="sidebar-nav">
          <button className="nav-item active">
            <span className="icon overview"></span> KYC Review
          </button>
          <button className="nav-item" onClick={() => setMessage('')}>
            <span className="icon transactions"></span> Actions
          </button>
        </nav>

        <div className="sidebar-footer">
          <button className="btn-logout" onClick={() => {
            localStorage.removeItem('token');
            localStorage.removeItem('isAdmin');
            navigate('/login');
          }}>Logout</button>
        </div>
      </aside>

      <main className="dashboard-main">
        <div className="content-section">
          <h2>Admin Panel</h2>
          <p>Review KYC submissions, approve or reject applications, and manage user verification status.</p>

          <div className="balance-display">
            <div className="balance-card-large" style={{ background: 'linear-gradient(135deg, #111827 0%, #1d4ed8 100%)' }}>
              <div className="balance-label">Pending KYC Applications</div>
              <div className="balance-amount">{pendingUsers.length}</div>
              <div className="balance-info">
                <div className="info-item">
                  <span className="label">Admin</span>
                  <span className="status verified">Access granted</span>
                </div>
                <div className="info-item">
                  <span className="label">Active account</span>
                  <span className="status">{user?.username}</span>
                </div>
              </div>
            </div>
          </div>

          {error && <div className="status-message error">{error}</div>}
          {message && <div className="status-message success">{message}</div>}

          <div className="card">
            <h3>Pending KYC Applications</h3>
            {pendingUsers.length === 0 ? (
              <p>No pending applications at the moment.</p>
            ) : (
              <div className="kyc-table">
                {pendingUsers.map((app) => (
                  <div key={app._id} className="kyc-card">
                    <div className="kyc-card-header">
                      <div>
                        <h4>{app.username}</h4>
                        <p>{app.email}</p>
                      </div>
                      <span className="status pending">Pending</span>
                    </div>

                    <div className="kyc-card-body">
                      <p><strong>Full name:</strong> {app.kycDetails.fullName || '–'}</p>
                      <p><strong>Country:</strong> {app.kycDetails.country || '–'}</p>
                      <p><strong>Phone:</strong> {app.kycDetails.countryCode || ''} {app.kycDetails.phoneNumber || '–'}</p>
                      <p><strong>Additional details:</strong> {app.kycDetails.additionalDetails || '–'}</p>

                      <div className="kyc-documents">
                        <div>
                          <span>ID Front:</span>
                          {app.kycDetails.idCardFront ? (
                            <a href={getFileUrl(app.kycDetails.idCardFront)} target="_blank" rel="noreferrer">View</a>
                          ) : 'Not uploaded'}
                        </div>
                        <div>
                          <span>ID Back:</span>
                          {app.kycDetails.idCardBack ? (
                            <a href={getFileUrl(app.kycDetails.idCardBack)} target="_blank" rel="noreferrer">View</a>
                          ) : 'Not uploaded'}
                        </div>
                      </div>
                    </div>

                    <div className="kyc-card-actions">
                      <button
                        className="btn-approve"
                        disabled={actionLoading === app._id}
                        onClick={() => changeKycStatus(app._id, 'approve')}
                      >
                        {actionLoading === app._id ? 'Processing...' : 'Approve'}
                      </button>
                      <button
                        className="btn-reject"
                        disabled={actionLoading === app._id}
                        onClick={() => changeKycStatus(app._id, 'reject')}
                      >
                        {actionLoading === app._id ? 'Processing...' : 'Reject'}
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </main>
    </div>
  );
};

export default AdminDashboard;
